/**
 * Deploy Paymaster to all configured chains.
 *
 * Usage:
 *   pnpm --filter @workspace/scripts run deploy-paymaster
 *
 * Reads from environment:
 *   DEPLOYER_PRIVATE_KEY  — deployer wallet private key (needs gas on each chain)
 *   FEE_RECIPIENT         — wallet address that receives deducted gas USDC
 *
 * Writes deployed addresses to:
 *   artifacts/arc-bridge/src/contracts/paymasterDeployments.json
 */

import { ethers } from "ethers";
import { writeFileSync, mkdirSync } from "fs";
import { resolve, dirname } from "path";
import { fileURLToPath } from "url";

const __dirname = dirname(fileURLToPath(import.meta.url));

const ABI = [
  "constructor(address _usdc, address _relayer, address _feeRecipient, uint256 _gasRate, address _entryPoint)",
  "function balances(address user) view returns (uint256)",
  "function locked(address user) view returns (uint256)",
  "function gasRate() view returns (uint256)",
  "function paused() view returns (bool)",
  "function relayer() view returns (address)",
  "function feeRecipient() view returns (address)",
  "function owner() view returns (address)",
  "function usdc() view returns (address)",
  "function entryPoint() view returns (address)",
  "function MAX_DEDUCTION_PER_TX() view returns (uint256)",
  "function deposit(uint256 amount)",
  "function withdraw(uint256 amount)",
  "function deductGas(address user, uint256 usdcCost)",
  "function validatePaymasterUserOp(tuple(address sender, uint256 nonce, bytes initCode, bytes callData, bytes32 accountGasLimits, uint256 preVerificationGas, bytes32 gasFees, bytes paymasterAndData, bytes signature) userOp, bytes32 userOpHash, uint256 maxCost) returns (bytes context, uint256 validationData)",
  "function postOp(uint8 mode, bytes context, uint256 actualGasCost, uint256 actualUserOpFeePerGas)",
  "function setRelayer(address newRelayer)",
  "function setFeeRecipient(address newRecipient)",
  "function setGasRate(uint256 newRate)",
  "function pause()",
  "function unpause()",
  "function transferOwnership(address newOwner)",
  "function acceptOwnership()",
  "function rescueTokens(address token, address to, uint256 amount)",
  "event Deposited(address indexed user, uint256 amount, uint256 newBalance)",
  "event Withdrawn(address indexed user, uint256 amount, uint256 remaining)",
  "event GasSponsored(address indexed user, uint256 usdcDeducted, uint256 remainingBalance)",
];

// ERC-4337 v0.7 EntryPoint — deployed via CREATE2, same address on all EVM chains.
const ENTRY_POINT_V07 = "0x0000000071727De22E5E9d8BAf0edAc6f37da032";

// Compiled from contracts/Paymaster.sol (solc 0.8.20, optimizer 200 runs, evmVersion paris)
// NOTE: This bytecode is from Paymaster v2 (4-param constructor). Paymaster v3 adds
// a 5th constructor param (_entryPoint) for ERC-4337 support. Regenerate by running:
//   npx solc --bin --optimize --optimize-runs 200 --evm-version paris contracts/Paymaster.sol
// then replace BYTECODE below and re-run deploy-paymaster.
// v2 contracts remain fully functional — v3 adds ERC-4337 on top.
const BYTECODE =
  "";

// 2 USDC-units per 1M gas units — rough estimate for L2 testnet gas costs
const GAS_RATE = 2n;

interface ChainTarget {
  name: string;
  rpcUrl: string;
  chainId: number;
  explorerUrl: string;
  usdc: string;
}

const CHAINS: ChainTarget[] = [
  {
    name: "Arc Testnet",
    rpcUrl: "https://rpc.drpc.testnet.arc.network",
    chainId: 5042002,
    explorerUrl: "https://testnet.arcscan.app",
    usdc: "0x3600000000000000000000000000000000000000",
  },
  {
    name: "Ethereum Sepolia",
    rpcUrl: "https://ethereum-sepolia-rpc.publicnode.com",
    chainId: 11155111,
    explorerUrl: "https://sepolia.etherscan.io",
    usdc: "0x1c7D4B196Cb0C7B01d743Fbc6116a902379C7238",
  },
  {
    name: "Base Sepolia",
    rpcUrl: "https://sepolia.base.org",
    chainId: 84532,
    explorerUrl: "https://sepolia.basescan.org",
    usdc: "0x036CbD53842c5426634e7929541eC2318f3dCF7e",
  },
  {
    name: "Avalanche Fuji",
    rpcUrl: "https://api.avax-test.network/ext/bc/C/rpc",
    chainId: 43113,
    explorerUrl: "https://testnet.snowtrace.io",
    usdc: "0x5425890298aed601595a70AB815c96711a31Bc65",
  },
];

async function deployToChain(
  chain: ChainTarget,
  privateKey: string,
  feeRecipient: string
): Promise<string> {
  console.log(`\n📡 Connecting to ${chain.name} (chainId ${chain.chainId})...`);

  const provider = new ethers.JsonRpcProvider(chain.rpcUrl);
  const wallet   = new ethers.Wallet(privateKey, provider);
  const address  = await wallet.getAddress();
  const balance  = await provider.getBalance(address);

  console.log(`   Deployer      : ${address}`);
  console.log(`   Balance       : ${ethers.formatEther(balance)} native`);
  console.log(`   USDC          : ${chain.usdc}`);
  console.log(`   Relayer       : ${address}  (deployer = initial relayer)`);
  console.log(`   Fee recipient : ${feeRecipient}`);
  console.log(`   Gas rate      : ${GAS_RATE} USDC-units per gas unit`);

  if (balance === 0n) {
    throw new Error(
      `No native balance on ${chain.name}. Fund the deployer wallet with testnet gas first.`
    );
  }

  const network = await provider.getNetwork();
  if (Number(network.chainId) !== chain.chainId) {
    throw new Error(`Chain ID mismatch: expected ${chain.chainId}, got ${network.chainId}`);
  }

  const factory  = new ethers.ContractFactory(ABI, BYTECODE, wallet);
  console.log(`   Deploying Paymaster…`);

  console.log(`   EntryPoint    : ${ENTRY_POINT_V07}  (ERC-4337 v0.7)`);

  // Deployer address is also the initial relayer so the contract is immediately usable
  const contract = await factory.deploy(chain.usdc, address, feeRecipient, GAS_RATE, ENTRY_POINT_V07);
  const deployed = await contract.waitForDeployment();
  const addr     = await deployed.getAddress();

  const explorerLink = chain.explorerUrl
    ? `${chain.explorerUrl}/address/${addr}`
    : addr;
  console.log(`   ✅ Address  : ${addr}`);
  console.log(`   🔍 Explorer : ${explorerLink}`);

  return addr;
}

async function main() {
  const privateKey   = process.env.DEPLOYER_PRIVATE_KEY;
  const feeRecipient = process.env.FEE_RECIPIENT;

  if (!privateKey)   throw new Error("DEPLOYER_PRIVATE_KEY secret is not set.");
  if (!feeRecipient) throw new Error("FEE_RECIPIENT secret is not set.");
  if (!ethers.isAddress(feeRecipient)) {
    throw new Error(`FEE_RECIPIENT is not a valid address: ${feeRecipient}`);
  }

  console.log("🚀 Paymaster Deployment");
  console.log("════════════════════════════════════════════════");
  console.log(`Fee recipient : ${feeRecipient}`);
  console.log(`Gas rate      : ${GAS_RATE} USDC-units per gas unit`);
  console.log(`Max deduction : 10 USDC per transaction`);

  const deployments: Record<string, string> = {};
  const failed: string[] = [];

  for (const chain of CHAINS) {
    try {
      deployments[chain.chainId.toString()] = await deployToChain(chain, privateKey, feeRecipient);
    } catch (err) {
      console.error(`\n❌ Failed on ${chain.name}: ${(err as Error).message}`);
      failed.push(chain.name);
    }
  }

  const outDir  = resolve(__dirname, "../../artifacts/arc-bridge/src/contracts");
  const outFile = resolve(outDir, "paymasterDeployments.json");
  mkdirSync(outDir, { recursive: true });
  writeFileSync(
    outFile,
    JSON.stringify({
      deployments,
      gasRate: GAS_RATE.toString(),
      feeRecipient,
    }, null, 2)
  );

  console.log("\n════════════════════════════════════════════════");
  console.log("📄 Deployment summary");
  for (const [chainId, addr] of Object.entries(deployments)) {
    const chain = CHAINS.find((c) => c.chainId.toString() === chainId);
    console.log(`   ${(chain?.name ?? chainId).padEnd(20)} ${addr}`);
  }

  if (failed.length > 0) {
    console.log(`\n⚠️  Failed chains: ${failed.join(", ")}`);
    process.exit(1);
  }

  console.log(`\n✅ Saved to: ${outFile}`);
  console.log("   Update PAYMASTER_ADDRESSES in lib/paymaster.ts and restart the bridge.\n");
}

main().catch((err) => {
  console.error("\n💥 Fatal:", err.message);
  process.exit(1);
});
